  1â†’import { useState, useEffect, useRef, useCallback } from "react";
  2â†’import { invoke } from "@tauri-apps/api/core";
  3â†’import { Sidebar } from "./features/repos/Sidebar";
  4â†’import { useReposQuery } from "./hooks/use-tauri-query";
  5â†’import { TitleBar } from "./components/TitleBar";
  6â†’import { TabBar } from "./components/TabBar";
  7â†’import { CheckpointList } from "./features/checkpoints/CheckpointList";
  8â†’import { TranscriptView } from "./features/transcripts/TranscriptView";
  9â†’import { DiffView, BranchDiffView } from "./features/diff/DiffView";
 10â†’import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
 11â†’import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
 12â†’import { BranchDebugContainer } from "./features/debug/BranchDebugContainer";
 13â†’import { CheckpointDebugContainer } from "./features/debug/CheckpointDebugContainer";
 14â†’import { TerminalPanel } from "./features/terminal/TerminalPanel";
 15â†’import type { TerminalPanelHandle } from "./features/terminal/TerminalPanel";
 16â†’import { createBranchTab, createWorktreeTab } from "./features/repos/tab-state";
 17â†’import { DEFAULT_SIDEBAR_WIDTH, clampSidebarWidth } from "./features/repos/sidebar-width.ts";
 18â†’import { planWorktreeDeletionCleanup } from "./features/repos/worktree-delete-state.ts";
 19â†’import {
 20â†’  collectWorkspaceSurfaceIds,
 21â†’  createTerminalWorkspace,
 22â†’  type TerminalWorkspace,
 23â†’  type WorkspaceUpdate,
 24â†’} from "./features/terminal/workspace";
 25â†’import {
 26â†’  createTerminalPanelVisibility,
 27â†’  isTerminalPanelOpen,
 28â†’  setTerminalPanelOpen,
 29â†’  syncTerminalPanelVisibility,
 30â†’} from "./features/terminal/panel-visibility";
 31â†’import {
 32â†’  DEFAULT_TERMINAL_HEIGHT,
 33â†’  clampTerminalHeight,
 34â†’} from "./features/terminal/resize.ts";
 35â†’import { useLiveUpdates } from "./hooks/use-live-updates";
 36â†’import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 37â†’import { SettingsView } from "./features/settings/SettingsView";
 38â†’import { ArrowLeft, GitCommit } from "lucide-react";
 39â†’
 40â†’export interface Tab {
 41â†’  id: string;
 42â†’  branch: string;
 43â†’  repoPath: string;
 44â†’  worktree: WorktreeInfo | null;
 45â†’  kind: "branch" | "agent";
 46â†’  agent: string | null;
 47â†’  hasActiveSession: boolean;
 48â†’}
 49â†’
 50â†’function resolveAgent(agent: string) {
 51â†’  return agent === "codex" ? "codex" : "claude-code";
 52â†’}
 53â†’
 54â†’export default function App() {
 55â†’  const [tabs, setTabs] = useState<Tab[]>([
 56â†’    {
 57â†’      id: "main",
 58â†’      branch: "main",
 59â†’      repoPath: "",
 60â†’      worktree: null,
 61â†’      kind: "branch",
 62â†’      agent: null,
 63â†’      hasActiveSession: false,
 64â†’    },
 65â†’  ]);
 66â†’  const [activeTabId, setActiveTabId] = useState("main");
 67â†’  const [sidebarWidth, setSidebarWidth] = useState(DEFAULT_SIDEBAR_WIDTH);
 68â†’  const [terminalHeight, setTerminalHeight] = useState(() => {
 69â†’    const storedHeight = Number(localStorage.getItem("entire:terminal-height"));
 70â†’    const initialHeight = Number.isFinite(storedHeight) && storedHeight > 0
 71â†’      ? storedHeight
 72â†’      : DEFAULT_TERMINAL_HEIGHT;
 73â†’
 74â†’    return clampTerminalHeight(initialHeight, window.innerHeight);
 75â†’  });
 76â†’  const [checkpointListWidth, setCheckpointListWidth] = useState(() => {
 77â†’    const stored = Number(localStorage.getItem("entire:checkpoint-list-width"));
 78â†’    return Number.isFinite(stored) && stored >= 200 ? Math.min(stored, 500) : 320;
 79â†’  });
 80â†’  const [terminalPanelVisibility, setTerminalPanelVisibility] = useState(
 81â†’    () => createTerminalPanelVisibility(["main"])
 82â†’  );
 83â†’  const [innerTab, setInnerTab] = useState<
 84â†’    "checkpoints" | "diff" | "insights" | "debug"
 85â†’  >("checkpoints");
 86â†’  const [selectedCheckpoint, setSelectedCheckpoint] =
 87â†’    useState<CheckpointSummary | null>(null);
 88â†’  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 89â†’    "transcript" | "diff" | "insights" | "debug"
 90â†’  >("transcript");
 91â†’
 92â†’  const [workspaceMap, setWorkspaceMap] = useState<Map<string, TerminalWorkspace>>(
 93â†’    () => new Map([["main", createTerminalWorkspace()]])
 94â†’  );
 95â†’  const [pendingAgentLaunch, setPendingAgentLaunch] = useState<{
 96â†’    tabId: string;
 97â†’    agent: string;
 98â†’    prompt: string;
 99â†’  } | null>(null);
100â†’  const [isSidebarDialogOpen, setIsSidebarDialogOpen] = useState(false);
101â†’  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
102â†’
103â†’  const terminalRef = useRef<TerminalPanelHandle>(null);
104â†’
105â†’  // Load repos so we can auto-populate the initial tab
106â†’  const { data: repos } = useReposQuery();
107â†’
108â†’  // Auto-populate the initial tab's repoPath from the first discovered repo
109â†’  useEffect(() => {
110â†’    invoke("debug_log", {
111â†’      message: `useEffect[repos]: repos=${repos ? repos.length : "null"}, first repo path=${repos?.[0]?.path ?? "none"}`,
112â†’    }).catch(() => {});
113â†’
114â†’    if (!repos || repos.length === 0) return;
115â†’    setTabs((prev) => {
116â†’      const updated = prev.map((tab) => {
117â†’        if (tab.id === "main" && !tab.repoPath) {
118â†’          const repo = repos[0];
119â†’          const headBranch = repo.branches.find((b: { is_head: boolean }) => b.is_head);
120â†’          const newPath = repo.path;
121â†’          const newBranch = headBranch?.name ?? repo.branches[0]?.name ?? "main";
122â†’          invoke("debug_log", {
123â†’            message: `Auto-populating initial tab: repoPath=${newPath}, branch=${newBranch}`,
124â†’          }).catch(() => {});
125â†’          return {
126â†’            ...tab,
127â†’            repoPath: newPath,
128â†’            branch: newBranch,
129â†’          };
130â†’        }
131â†’        return tab;
132â†’      });
133â†’      return updated;
134â†’    });
135â†’  }, [repos]);
136â†’
137â†’  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
138â†’  const activeWorkspace =
139â†’    workspaceMap.get(activeTabId) ?? createTerminalWorkspace();
140â†’  const isTerminalOpen = isTerminalPanelOpen(terminalPanelVisibility, activeTabId);
141â†’  const tabsWithSessions = tabs.map((tab) => ({
142â†’    ...tab,
143â†’    hasActiveSession: collectWorkspaceSurfaceIds(workspaceMap.get(tab.id)).length > 0,
144â†’  }));
145â†’
146â†’  // Live updates â€” watch active repo for checkpoint/session changes
147â†’  useLiveUpdates(activeTab.repoPath);
148â†’
149â†’  useEffect(() => {
150â†’    setWorkspaceMap((prev) => {
151â†’      let changed = false;
152â†’      const next = new Map(prev);
153â†’      for (const tab of tabs) {
154â†’        if (!next.has(tab.id)) {
155â†’          next.set(tab.id, createTerminalWorkspace());
156â†’          changed = true;
157â†’        }
158â†’      }
159â†’      return changed ? next : prev;
160â†’    });
161â†’  }, [tabs]);
162â†’
163â†’  useEffect(() => {
164â†’    setTerminalPanelVisibility((prev) =>
165â†’      syncTerminalPanelVisibility(
166â†’        prev,
167â†’        tabs.map((tab) => tab.id)
168â†’      )
169â†’    );
170â†’  }, [tabs]);
171â†’
172â†’  const handleWorkspaceChange = useCallback(
173â†’    (tabId: string, update: WorkspaceUpdate) => {
174â†’      setWorkspaceMap((prev) => {
175â†’        const next = new Map(prev);
176â†’        const current = next.get(tabId) ?? createTerminalWorkspace();
177â†’        next.set(
178â†’          tabId,
179â†’          typeof update === "function" ? update(current) : update
180â†’        );
181â†’        return next;
182â†’      });
183â†’    },
184â†’    []
185â†’  );
186â†’
187â†’  const handleSetTerminalOpen = useCallback((tabId: string, isOpen: boolean) => {
188â†’    setTerminalPanelVisibility((prev) => setTerminalPanelOpen(prev, tabId, isOpen));
189â†’  }, []);
190â†’
191â†’  // Terminal dispatch â€” open shell and optionally send a prompt
192â†’  const handleSendToAgent = useCallback(
193â†’    (agent: string, prompt: string) => {
194â†’      if (!activeTab.repoPath) return;
195â†’
196â†’      const resolvedAgent = resolveAgent(agent);
197â†’      const tabId = `agent:${resolvedAgent}:${Date.now()}`;
198â†’      const agentTab: Tab = {
199â†’        id: tabId,
200â†’        branch: activeTab.branch,
201â†’        repoPath: activeTab.repoPath,
202â†’        worktree: activeTab.worktree,
203â†’        kind: "agent",
204â†’        agent: resolvedAgent,
205â†’        hasActiveSession: false,
206â†’      };
207â†’
208â†’      setTabs((prev) => [...prev, agentTab]);
209â†’      setActiveTabId(tabId);
210â†’      handleSetTerminalOpen(tabId, true);
211â†’      setPendingAgentLaunch({ tabId, agent: resolvedAgent, prompt });
212â†’    },
213â†’    [activeTab, handleSetTerminalOpen]
214â†’  );
215â†’
216â†’  useEffect(() => {
217â†’    if (!pendingAgentLaunch) return;
218â†’    if (pendingAgentLaunch.tabId !== activeTabId) return;
219â†’    if (!isTerminalOpen) return;
220â†’
221â†’    let cancelled = false;
222â†’    let timer = 0;
223â†’
224â†’    const launch = () => {
225â†’      if (cancelled) return;
226â†’      if (!terminalRef.current) {
227â†’        timer = window.setTimeout(launch, 50);
228â†’        return;
229â†’      }
230â†’
231â†’      terminalRef.current
232â†’        .launchSession({
233â†’          agent: pendingAgentLaunch.agent,
234â†’          prompt: pendingAgentLaunch.prompt,
235â†’        })
236â†’        .finally(() => {
237â†’          setPendingAgentLaunch((current) =>
238â†’            current?.tabId === pendingAgentLaunch.tabId ? null : current
239â†’          );
240â†’        });
241â†’    };
242â†’
243â†’    timer = window.setTimeout(launch, 50);
244â†’    return () => {
245â†’      cancelled = true;
246â†’      window.clearTimeout(timer);
247â†’    };
248â†’  }, [activeTabId, isTerminalOpen, pendingAgentLaunch]);
249â†’
250â†’  // Persist UI state to localStorage
251â†’  useEffect(() => {
252â†’    localStorage.setItem("entire:terminal-height", String(terminalHeight));
253â†’  }, [terminalHeight]);
254â†’  useEffect(() => {
255â†’    localStorage.setItem("entire:checkpoint-list-width", String(checkpointListWidth));
256â†’  }, [checkpointListWidth]);
257â†’  useEffect(() => {
258â†’    function handleWindowResize() {
259â†’      setTerminalHeight((currentHeight) =>
260â†’        clampTerminalHeight(currentHeight, window.innerHeight)
261â†’      );
262â†’    }
263â†’
264â†’    window.addEventListener("resize", handleWindowResize);
265â†’    return () => window.removeEventListener("resize", handleWindowResize);
266â†’  }, []);
267â†’
268â†’  // Clear selected checkpoint when switching branch tabs
269â†’  useEffect(() => {
270â†’    setSelectedCheckpoint(null);
271â†’    setCheckpointInnerTab("transcript");
272â†’  }, [activeTabId]);
273â†’
274â†’  // Keyboard shortcuts
275â†’  useEffect(() => {
276â†’    function onKeyDown(e: KeyboardEvent) {
277â†’      const meta = e.metaKey || e.ctrlKey;
278â†’
279â†’      // Cmd+K = focus search
280â†’      if (meta && e.key === "k") {
281â†’        e.preventDefault();
282â†’        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
283â†’      }
284â†’      // Ctrl+` = toggle terminal
285â†’      if (e.ctrlKey && e.key === "`") {
286â†’        e.preventDefault();
287â†’        handleSetTerminalOpen(activeTabId, !isTerminalOpen);
288â†’      }
289â†’      // Cmd+W = close active tab
290â†’      if (meta && e.key === "w") {
291â†’        e.preventDefault();
292â†’        handleCloseTab(activeTabId);
293â†’      }
294â†’      // Cmd+1-9 = switch to tab by index
295â†’      if (meta && e.key >= "1" && e.key <= "9") {
296â†’        e.preventDefault();
297â†’        const idx = parseInt(e.key) - 1;
298â†’        if (idx < tabs.length) {
299â†’          setActiveTabId(tabs[idx].id);
300â†’        }
301â†’      }
302â†’      // Cmd+[ / Cmd+] = prev/next tab
303â†’      if (meta && e.key === "[") {
304â†’        e.preventDefault();
305â†’        const idx = tabs.findIndex((t) => t.id === activeTabId);
306â†’        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
307â†’      }
308â†’      if (meta && e.key === "]") {
309â†’        e.preventDefault();
310â†’        const idx = tabs.findIndex((t) => t.id === activeTabId);
311â†’        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
312â†’      }
313â†’      // Escape = deselect checkpoint
314â†’      if (e.key === "Escape" && selectedCheckpoint) {
315â†’        setSelectedCheckpoint(null);
316â†’      }
317â†’    }
318â†’    window.addEventListener("keydown", onKeyDown);
319â†’    return () => window.removeEventListener("keydown", onKeyDown);
320â†’  }, [activeTabId, handleSetTerminalOpen, isTerminalOpen, tabs, selectedCheckpoint]);
321â†’
322â†’  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
323â†’    const newTab = createBranchTab(branch, repoPath);
324â†’    const existing = tabs.find(
325â†’      (t) =>
326â†’        t.kind === "branch" &&
327â†’        t.branch === newTab.branch &&
328â†’        t.repoPath === newTab.repoPath
329â†’    );
330â†’    if (existing) {
331â†’      setActiveTabId(existing.id);
332â†’    } else {
333â†’      setTabs([...tabs, newTab]);
334â†’      setActiveTabId(newTab.id);
335â†’    }
336â†’  }
337â†’
338â†’  function handleWorktreeSelect(wt: WorktreeInfo) {
339â†’    const newTab = createWorktreeTab(wt);
340â†’    const existing = tabs.find(
341â†’      (t) =>
342â†’        t.kind === "branch" &&
343â†’        t.branch === newTab.branch &&
344â†’        t.repoPath === newTab.repoPath
345â†’    );
346â†’    if (existing) {
347â†’      setActiveTabId(existing.id);
348â†’    } else {
349â†’      setTabs([...tabs, newTab]);
350â†’      setActiveTabId(newTab.id);
351â†’    }
352â†’  }
353â†’
354â†’  function handleCloseTab(tabId: string) {
355â†’    if (tabs.length <= 1) return;
356â†’    const idx = tabs.findIndex((t) => t.id === tabId);
357â†’    const newTabs = tabs.filter((t) => t.id !== tabId);
358â†’    setTabs(newTabs);
359â†’    if (activeTabId === tabId) {
360â†’      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
361â†’    }
362â†’    const closedWorkspace = workspaceMap.get(tabId);
363â†’    for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
364â†’      invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
365â†’    }
366â†’    setWorkspaceMap((prev) => {
367â†’      const next = new Map(prev);
368â†’      next.delete(tabId);
369â†’      return next;
370â†’    });
371â†’  }
372â†’
373â†’  function handleBranchDeleted(branchName: string, repoPath: string) {
374â†’    const tabsToRemove = tabs.filter(
375â†’      (tab) =>
376â†’        tab.kind === "branch" &&
377â†’        tab.worktree === null &&
378â†’        tab.branch === branchName &&
379â†’        tab.repoPath === repoPath
380â†’    );
381â†’
382â†’    if (tabsToRemove.length === 0) {
383â†’      return;
384â†’    }
385â†’
386â†’    const nextTabs = tabs.filter((tab) => !tabsToRemove.some((candidate) => candidate.id === tab.id));
387â†’    setTabs(nextTabs);
388â†’
389â†’    if (tabsToRemove.some((tab) => tab.id === activeTabId) && nextTabs.length > 0) {
390â†’      setActiveTabId(nextTabs[0].id);
391â†’    }
392â†’
393â†’    setWorkspaceMap((prev) => {
394â†’      const next = new Map(prev);
395â†’      for (const tab of tabsToRemove) {
396â†’        const closedWorkspace = next.get(tab.id);
397â†’        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
398â†’          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
399â†’        }
400â†’        next.delete(tab.id);
401â†’      }
402â†’      return next;
403â†’    });
404â†’  }
405â†’
406â†’  function handleWorktreeDeleted(worktreePath: string) {
407â†’    const cleanup = planWorktreeDeletionCleanup({
408â†’      tabs,
409â†’      activeTabId,
410â†’      worktreePath,
411â†’    });
412â†’
413â†’    if (cleanup.removedTabIds.length === 0) {
414â†’      return;
415â†’    }
416â†’
417â†’    setTabs(cleanup.remainingTabs);
418â†’
419â†’    if (cleanup.nextActiveTabId && cleanup.nextActiveTabId !== activeTabId) {
420â†’      setActiveTabId(cleanup.nextActiveTabId);
421â†’    }
422â†’
423â†’    setWorkspaceMap((prev) => {
424â†’      const next = new Map(prev);
425â†’      for (const tabId of cleanup.removedTabIds) {
426â†’        const closedWorkspace = next.get(tabId);
427â†’        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
428â†’          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
429â†’        }
430â†’        next.delete(tabId);
431â†’      }
432â†’      return next;
433â†’    });
434â†’  }
435â†’
436â†’  function handleResizeStart(e: React.MouseEvent) {
437â†’    e.preventDefault();
438â†’    const startY = e.clientY;
439â†’    const startHeight = terminalHeight;
440â†’
441â†’    function onMouseMove(ev: MouseEvent) {
442â†’      const delta = startY - ev.clientY;
443â†’      setTerminalHeight(
444â†’        clampTerminalHeight(startHeight + delta, window.innerHeight)
445â†’      );
446â†’    }
447â†’    function onMouseUp() {
448â†’      window.removeEventListener("mousemove", onMouseMove);
449â†’      window.removeEventListener("mouseup", onMouseUp);
450â†’    }
451â†’    window.addEventListener("mousemove", onMouseMove);
452â†’    window.addEventListener("mouseup", onMouseUp);
453â†’  }
454â†’
455â†’  function handleSidebarResizeStart(e: React.MouseEvent<HTMLDivElement>) {
456â†’    e.preventDefault();
457â†’    const startX = e.clientX;
458â†’    const startWidth = sidebarWidth;
459â†’
460â†’    function onMouseMove(ev: MouseEvent) {
461â†’      const delta = ev.clientX - startX;
462â†’      setSidebarWidth(clampSidebarWidth(startWidth + delta));
463â†’    }
464â†’
465â†’    function onMouseUp() {
466â†’      window.removeEventListener("mousemove", onMouseMove);
467â†’      window.removeEventListener("mouseup", onMouseUp);
468â†’    }
469â†’
470â†’    window.addEventListener("mousemove", onMouseMove);
471â†’    window.addEventListener("mouseup", onMouseUp);
472â†’  }
473â†’
474â†’  function handleCheckpointListResizeStart(e: React.MouseEvent<HTMLDivElement>) {
475â†’    e.preventDefault();
476â†’    const startX = e.clientX;
477â†’    const startWidth = checkpointListWidth;
478â†’
479â†’    function onMouseMove(ev: MouseEvent) {
480â†’      const delta = ev.clientX - startX;
481â†’      setCheckpointListWidth(Math.max(200, Math.min(500, startWidth + delta)));
482â†’    }
483â†’
484â†’    function onMouseUp() {
485â†’      window.removeEventListener("mousemove", onMouseMove);
486â†’      window.removeEventListener("mouseup", onMouseUp);
487â†’    }
488â†’
489â†’    window.addEventListener("mousemove", onMouseMove);
490â†’    window.addEventListener("mouseup", onMouseUp);
491â†’  }
492â†’
493â†’  const repoName = activeTab.repoPath
494â†’    ? activeTab.repoPath.split("/").pop()
495â†’    : "";
496â†’
497â†’  return (
498â†’    <div className="flex h-screen flex-col">
499â†’      <TitleBar
500â†’        title={`Entire â€” ${repoName ? `${repoName}/` : ""}${activeTab?.branch ?? ""}`}
501â†’      />
502â†’
503â†’      <div className="flex flex-1 overflow-hidden">
504â†’        {/* Sidebar */}
505â†’        <Sidebar
506â†’          activeTab={activeTab}
507â†’          width={sidebarWidth}
508â†’          onBranchSelect={handleBranchSelect}
509â†’          onBranchDeleted={handleBranchDeleted}
510â†’          onWorktreeDeleted={handleWorktreeDeleted}
511â†’          onWorktreeSelect={handleWorktreeSelect}
512â†’          onResizeStart={handleSidebarResizeStart}
513â†’          onDialogOpen={setIsSidebarDialogOpen}
514â†’          onOpenSettings={() => setIsSettingsOpen(true)}
515â†’        />
516â†’
517â†’        {/* Main content */}
518â†’        <div className="flex flex-1 flex-col overflow-hidden">
519â†’          <TabBar
520â†’            tabs={tabsWithSessions}
521â†’            activeTabId={activeTabId}
522â†’            onSelectTab={setActiveTabId}
523â†’            onCloseTab={handleCloseTab}
524â†’          />
525â†’
526â†’          <div className="flex flex-1 flex-col overflow-hidden">
527â†’            {/* Inner tabs */}
528â†’            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
529â†’              {(["checkpoints", "diff", "insights", "debug"] as const).map((tab) => (
530â†’                <button
531â†’                  key={tab}
532â†’                  onClick={() => setInnerTab(tab)}
533â†’                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
534â†’                    innerTab === tab
535â†’                      ? "border-accent text-fg"
536â†’                      : "border-transparent text-fg-subtle hover:text-fg-muted"
537â†’                  }`}
538â†’                >
539â†’                  {tab === "checkpoints"
540â†’                    ? "Checkpoints"
541â†’                    : tab === "diff"
542â†’                      ? "Diff"
543â†’                      : tab === "insights"
544â†’                        ? "Insights"
545â†’                        : "Debug"}
546â†’                </button>
547â†’              ))}
548â†’            </div>
