 25â†’pub fn sanitize_transcript_for_semantic_review(
 26â†’    messages: &[TranscriptMessage],
 27â†’    max_chars: usize,
 28â†’) -> Vec<TranscriptMessage> {
 29â†’    let sanitized: Vec<TranscriptMessage> = messages
 30â†’        .iter()
 31â†’        .filter_map(|message| match message.role.as_str() {
 32â†’            "user" | "assistant" if message.tool_name.is_none() => {
 33â†’                let content = message.content.trim();
 34â†’                if content.is_empty() {
 35â†’                    None
 36â†’                } else {
 37â†’                    Some(TranscriptMessage {
 38â†’                        role: message.role.clone(),
 39â†’                        content: content.to_string(),
 40â†’                        tool_name: None,
 41â†’                        tool_input: None,
 42â†’                        timestamp: message.timestamp.clone(),
 43â†’                    })
 44â†’                }
 45â†’            }
 46â†’            "assistant" => message.tool_name.as_ref().map(|tool_name| TranscriptMessage {
 47â†’                role: "assistant".to_string(),
 48â†’                content: format!("used tool {}.", tool_name),
 49â†’                tool_name: None,
 50â†’                tool_input: None,
 51â†’                timestamp: message.timestamp.clone(),
 52â†’            }),
 53â†’            _ => None,
 54â†’        })
 55â†’        .collect();
 56â†’
 57â†’    if max_chars == 0 {
 58â†’        return Vec::new();
 59â†’    }
 60â†’
 61â†’    let mut kept = Vec::new();
 62â†’    let mut used = 0usize;
 63â†’
 64â†’    for message in sanitized.into_iter().rev() {
 65â†’        let len = message.content.chars().count();
 66â†’        if kept.is_empty() && len > max_chars {
 67â†’            kept.push(TranscriptMessage {
 68â†’                content: truncate_for_budget(&message.content, max_chars),
 69â†’                ..message
 70â†’            });
 71â†’            break;
 72â†’        }
 73â†’
 74â†’        if used + len > max_chars {
 75â†’            continue;
 76â†’        }
 77â†’
 78â†’        used += len;
 79â†’        kept.push(message);
 80â†’    }
 81â†’
 82â†’    kept.reverse();
 83â†’    kept
 84â†’}
