 86â†’fn truncate_for_budget(content: &str, max_chars: usize) -> String {
 87â†’    let chars: Vec<char> = content.chars().collect();
 88â†’    if chars.len() <= max_chars {
 89â†’        return content.to_string();
 90â†’    }
 91â†’
 92â†’    chars[..max_chars].iter().collect()
 93â†’}
