 39â†’pub fn list_branches(repo: &Repository) -> Result<Vec<BranchInfo>, String> {
 40â†’    let mut branches = Vec::new();
 41â†’    let head = repo.head().ok();
 42â†’    let head_name = head
 43â†’        .as_ref()
 44â†’        .and_then(|h| h.shorthand().map(|s| s.to_string()));
 45â†’
 46â†’    let git_branches = repo
 47â†’        .branches(Some(git2::BranchType::Local))
 48â†’        .map_err(|e| format!("Failed to list branches: {}", e))?;
 49â†’
 50â†’    for branch_result in git_branches {
 51â†’        let (branch, _) = branch_result.map_err(|e| format!("Branch error: {}", e))?;
 52â†’        if let Some(name) = branch.name().ok().flatten() {
 53â†’            // Skip entire/ internal branches
 54â†’            if name.starts_with("entire/") {
 55â†’                continue;
 56â†’            }
 57â†’            branches.push(BranchInfo {
 58â†’                is_head: head_name.as_deref() == Some(name),
 59â†’                name: name.to_string(),
 60â†’                checkpoint_count: 0, // TODO: count from checkpoint branch
 61â†’            });
 62â†’        }
 63â†’    }
 64â†’
 65â†’    Ok(branches)
 66â†’}
