117â†’#[tauri::command]
118â†’fn get_transcript(
119â†’    repo_path: String,
120â†’    checkpoint_id: String,
121â†’    session_index: u32,
122â†’) -> Result<Vec<session::TranscriptMessage>, String> {
123â†’    let repo = git::open_repo(&repo_path)?;
124â†’
125â†’    let prefix = &checkpoint_id[..2];
126â†’    let suffix = &checkpoint_id[2..];
127â†’    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
128â†’    let meta_content = read_blob(&repo, &meta_path).ok();
129â†’    let candidates =
130â†’        transcript_candidate_paths(&checkpoint_id, session_index, meta_content.as_deref());
131â†’
132â†’    for path in &candidates {
133â†’        if let Ok(content) = read_blob(&repo, path) {
134â†’            return Ok(session::read_transcript(&content));
135â†’        }
136â†’    }
137â†’
138â†’    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
139â†’}
