141â†’fn transcript_candidate_paths(
142â†’    checkpoint_id: &str,
143â†’    session_index: u32,
144â†’    meta_content: Option<&str>,
145â†’) -> Vec<String> {
146â†’    let prefix = &checkpoint_id[..2];
147â†’    let suffix = &checkpoint_id[2..];
148â†’    let requested_session_dir = format!("{}/{}/{}", prefix, suffix, session_index);
149â†’    let mut candidates = Vec::new();
150â†’
151â†’    let mut push_candidate = |path: String| {
152â†’        if !path.is_empty() && !candidates.contains(&path) {
153â†’            candidates.push(path);
154â†’        }
155â†’    };
156â†’
157â†’    if let Some(meta_content) = meta_content {
158â†’        if let Ok(meta) = serde_json::from_str::<serde_json::Value>(meta_content) {
159â†’            if let Some(sessions) = meta.get("sessions").and_then(|s| s.as_array()) {
160â†’                let mut ordered_sessions = Vec::new();
161â†’                if let Some(session) = sessions.get(session_index as usize) {
162â†’                    ordered_sessions.push(session);
163â†’                }
164â†’                for (idx, session) in sessions.iter().enumerate() {
165â†’                    if idx != session_index as usize {
166â†’                        ordered_sessions.push(session);
167â†’                    }
168â†’                }
169â†’
170â†’                for session in ordered_sessions {
171â†’                    if let Some(path) = session.get("transcript").and_then(|p| p.as_str()) {
172â†’                        push_candidate(path.trim_start_matches('/').to_string());
173â†’                    }
174â†’                }
175â†’            }
176â†’        }
177â†’    }
178â†’
179â†’    push_candidate(format!("{}/full.jsonl", requested_session_dir));
180â†’    push_candidate(format!("{}/transcript.jsonl", requested_session_dir));
181â†’    candidates
182â†’}
