184â†’/// Read a blob from the entire/checkpoints/v1 branch by path
185â†’fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
186â†’    let branch_ref = repo
187â†’        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
188â†’        .map_err(|e| format!("No checkpoint branch: {}", e))?;
189â†’
190â†’    let commit = branch_ref
191â†’        .get()
192â†’        .peel_to_commit()
193â†’        .map_err(|e| format!("Failed to peel: {}", e))?;
194â†’
195â†’    let tree = commit
196â†’        .tree()
197â†’        .map_err(|e| format!("Failed to get tree: {}", e))?;
198â†’
199â†’    let entry = tree
200â†’        .get_path(std::path::Path::new(path))
201â†’        .map_err(|e| format!("Path not found: {}", e))?;
202â†’
203â†’    let blob = repo
204â†’        .find_blob(entry.id())
205â†’        .map_err(|e| format!("Failed to read blob: {}", e))?;
206â†’
207â†’    std::str::from_utf8(blob.content())
208â†’        .map(|s| s.to_string())
209â†’        .map_err(|e| format!("Invalid UTF-8: {}", e))
210â†’}
