 3â†’export interface Insight {
 4â†’  content: string;
 5â†’  checkpointId: string;
 6â†’  commitMessage: string;
 7â†’  commitSha: string;
 8â†’  timestamp: string | null;
 9â†’}
10â†’
11â†’const INSIGHT_REGEX = /`?âک…\s*Insight\s*â”€+`?\s*\n([\s\S]*?)\n`?â”€{5,}`?/g;
12â†’
13â†’export function extractInsights(
14â†’  messages: TranscriptMessage[],
15â†’  checkpoint: CheckpointSummary
16â†’): Insight[] {
17â†’  const insights: Insight[] = [];
18â†’
19â†’  for (const msg of messages) {
20â†’    if (msg.role !== "assistant") continue;
21â†’
22â†’    let match: RegExpExecArray | null;
23â†’    INSIGHT_REGEX.lastIndex = 0;
24â†’    while ((match = INSIGHT_REGEX.exec(msg.content)) !== null) {
25â†’      insights.push({
26â†’        content: match[1].trim(),
27â†’        checkpointId: checkpoint.checkpoint_id,
28â†’        commitMessage: checkpoint.commit_message,
29â†’        commitSha: checkpoint.commit_sha,
30â†’        timestamp: msg.timestamp,
31â†’      });
32â†’    }
33â†’  }
34â†’
35â†’  return insights;
36â†’}
