 20â†’#[tauri::command]
 21â†’fn debug_log(message: String) -> Result<(), String> {
 22â†’    use std::io::Write;
 23â†’    let timestamp = std::time::SystemTime::now()
 24â†’        .duration_since(std::time::UNIX_EPOCH)
 25â†’        .unwrap_or_default();
 26â†’    let line = format!(
 27â†’        "[{}.{:03}] [frontend] {}\n",
 28â†’        timestamp.as_secs(),
 29â†’        timestamp.subsec_millis(),
 30â†’        message
 31â†’    );
 32â†’    std::fs::OpenOptions::new()
 33â†’        .create(true)
 34â†’        .append(true)
 35â†’        .open("/tmp/entire-terminal-debug.log")
 36â†’        .and_then(|mut f| f.write_all(line.as_bytes()))
 37â†’        .map_err(|e| format!("Failed to write debug log: {}", e))
 38â†’}
