 40â†’#[tauri::command]
 41â†’fn list_repos() -> Result<Vec<git::RepoInfo>, String> {
 42â†’    let repo_paths = config::discover_repos();
 43â†’    let registered = config::get_registered_repos();
 44â†’    let registered_set: HashSet<String> = registered.into_iter().collect();
 45â†’    let mut repos = Vec::new();
 46â†’    for path in repo_paths {
 47â†’        match git::get_repo_info(&path) {
 48â†’            Ok(mut info) => {
 49â†’                info.registered = registered_set.contains(&path);
 50â†’                repos.push(info);
 51â†’            }
 52â†’            Err(e) => eprintln!("Skipping repo {}: {}", path, e),
 53â†’        }
 54â†’    }
 55â†’    Ok(repos)
 56â†’}
