487â†’fn collect_checkpoint_diff(
488â†’    repo: &git2::Repository,
489â†’    commit_sha: &str,
490â†’) -> Result<Vec<FileDiff>, String> {
491â†’    let oid = git2::Oid::from_str(commit_sha)
492â†’        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
493â†’    let commit = repo
494â†’        .find_commit(oid)
495â†’        .map_err(|e| format!("Commit not found: {}", e))?;
496â†’
497â†’    let tree = commit
498â†’        .tree()
499â†’        .map_err(|e| format!("Failed to get tree: {}", e))?;
500â†’
501â†’    let parent_tree = commit.parent(0).ok().and_then(|p| p.tree().ok());
502â†’
503â†’    let diff = repo
504â†’        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
505â†’        .map_err(|e| format!("Failed to compute diff: {}", e))?;
506â†’
507â†’    collect_diff_files(&diff)
508â†’}
