510â†’fn load_sanitized_checkpoint_transcripts(
511â†’    repo: &git2::Repository,
512â†’    checkpoint_id: &str,
513â†’) -> Result<Vec<semantic_review::PromptTranscriptSession>, String> {
514â†’    let prefix = &checkpoint_id[..2];
515â†’    let suffix = &checkpoint_id[2..];
516â†’    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
517â†’    let meta_content = read_blob(repo, &meta_path)?;
518â†’    let meta = serde_json::from_str::<CheckpointReviewMetadata>(&meta_content)
519â†’        .map_err(|e| format!("Failed to parse checkpoint metadata: {}", e))?;
520â†’
521â†’    let session_count = meta.sessions.map(|sessions| sessions.len()).unwrap_or(0);
522â†’    let mut all_sessions = Vec::new();
523â†’
524â†’    for session_index in 0..session_count {
525â†’        let candidates =
526â†’            transcript_candidate_paths(checkpoint_id, session_index as u32, Some(&meta_content));
527â†’        let mut transcript_content = None;
528â†’        for path in candidates {
529â†’            if let Ok(content) = read_blob(repo, &path) {
530â†’                transcript_content = Some(content);
531â†’                break;
532â†’            }
533â†’        }
534â†’
535â†’        let Some(content) = transcript_content else {
536â†’            continue;
537â†’        };
538â†’
539â†’        let parsed = session::read_transcript(&content);
540â†’        let sanitized = session::sanitize_transcript_for_semantic_review(&parsed, 4_000);
541â†’        if sanitized.is_empty() {
542â†’            continue;
543â†’        }
544â†’
545â†’        all_sessions.push(semantic_review::PromptTranscriptSession {
546â†’            session_index: session_index as u32,
547â†’            messages: sanitized
548â†’                .into_iter()
549â†’                .map(|message| semantic_review::PromptTranscriptMessage {
550â†’                    role: message.role,
551â†’                    content: message.content,
552â†’                })
553â†’                .collect(),
554â†’        });
555â†’    }
556â†’
557â†’    Ok(all_sessions)
558â†’}
