560â†’fn call_anthropic_semantic_review(prompt: &str) -> Result<String, String> {
561â†’    let api_key = config::read_app_settings()
562â†’        .anthropic_api_key
563â†’        .filter(|k| !k.is_empty())
564â†’        .or_else(|| std::env::var("ANTHROPIC_API_KEY").ok())
565â†’        .ok_or_else(|| "Anthropic API key is not configured. Set it in Settings or as ANTHROPIC_API_KEY env var.".to_string())?;
566â†’    let model = std::env::var("ANTHROPIC_MODEL")
567â†’        .unwrap_or_else(|_| "claude-sonnet-4-20250514".to_string());
568â†’
569â†’    let client = reqwest::blocking::Client::builder()
570â†’        .timeout(std::time::Duration::from_secs(90))
571â†’        .build()
572â†’        .map_err(|e| format!("Failed to build Anthropic client: {}", e))?;
573â†’
574â†’    let response = client
575â†’        .post("https://api.anthropic.com/v1/messages")
576â†’        .header("x-api-key", api_key)
577â†’        .header("anthropic-version", "2023-06-01")
578â†’        .header("content-type", "application/json")
579â†’        .json(&AnthropicRequest {
580â†’            model,
581â†’            max_tokens: 2_000,
582â†’            temperature: 0.2,
583â†’            system: "You are reviewing a git diff. Return JSON only with precise, line-linked explanations of the most important changes.".to_string(),
584â†’            messages: vec![AnthropicMessage {
585â†’                role: "user".to_string(),
586â†’                content: prompt.to_string(),
587â†’            }],
588â†’        })
589â†’        .send()
590â†’        .map_err(|e| format!("Anthropic request failed: {}", e))?
591â†’        .error_for_status()
592â†’        .map_err(|e| format!("Anthropic request failed: {}", e))?;
593â†’
594â†’    let body: AnthropicResponse = response
595â†’        .json()
596â†’        .map_err(|e| format!("Failed to decode Anthropic response: {}", e))?;
597â†’
598â†’    let text = body
599â†’        .content
600â†’        .into_iter()
601â†’        .filter(|block| block.kind == "text")
602â†’        .filter_map(|block| block.text)
603â†’        .collect::<Vec<_>>()
604â†’        .join("\n");
605â†’
606â†’    if text.trim().is_empty() {
