633â†’#[tauri::command]
634â†’fn run_checkpoint_semantic_review(
635â†’    repo_path: String,
636â†’    checkpoint_id: String,
637â†’    commit_sha: String,
638â†’) -> Result<semantic_review::RunCheckpointSemanticReviewResponse, String> {
639â†’    if checkpoint_id.len() < 2 {
640â†’        return Err("Invalid checkpoint ID".to_string());
641â†’    }
642â†’    if commit_sha.is_empty() {
643â†’        return Err("No commit SHA available for this checkpoint".to_string());
644â†’    }
645â†’
646â†’    let repo = git::open_repo(&repo_path)?;
647â†’    let files = collect_checkpoint_diff(&repo, &commit_sha)?;
648â†’    if files.is_empty() {
649â†’        return Ok(semantic_review::RunCheckpointSemanticReviewResponse {
650â†’            review_run_id: generate_review_run_id(),
651â†’            annotations: Vec::new(),
652â†’        });
653â†’    }
654â†’
655â†’    let transcripts = load_sanitized_checkpoint_transcripts(&repo, &checkpoint_id)?;
656â†’    let prompt = semantic_review::build_prompt(&files, &transcripts);
657â†’    let raw_text = call_anthropic_semantic_review(&prompt)?;
658â†’    let parsed = semantic_review::parse_response_text(&raw_text)?;
659â†’    let annotations = semantic_review::resolve_annotations(&files, parsed);
660â†’
661â†’    Ok(semantic_review::RunCheckpointSemanticReviewResponse {
662â†’        review_run_id: generate_review_run_id(),
663â†’        annotations,
664â†’    })
