727â†’#[tauri::command]
728â†’fn watch_repo(
729â†’    repo_path: String,
730â†’    app: tauri::AppHandle,
731â†’    state: State<'_, Mutex<AppState>>,
732â†’) -> Result<(), String> {
733â†’    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
734â†’
735â†’    // Don't double-watch
736â†’    if app_state.watched_repos.contains(&repo_path) {
737â†’        return Ok(());
738â†’    }
739â†’    app_state.watched_repos.insert(repo_path.clone());
740â†’
741â†’    let app_handle = app.clone();
742â†’    let repo_path_for_closure = repo_path.clone();
743â†’    watcher::watch_repo(&repo_path, move |event| {
744â†’        let event_name = match event {
745â†’            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
746â†’            watcher::WatchEvent::SessionChanged(_) => "session-changed",
747â†’            watcher::WatchEvent::ConfigChanged => "config-changed",
748â†’        };
749â†’        let _ = app_handle.emit(event_name, serde_json::json!({
750â†’            "repoPath": repo_path_for_closure,
751â†’        }));
752â†’    })?;
753â†’
754â†’    Ok(())
755â†’}
