757â†’#[cfg_attr(mobile, tauri::mobile_entry_point)]
758â†’pub fn run() {
759â†’    tauri::Builder::default()
760â†’        .plugin(tauri_plugin_opener::init())
761â†’        .plugin(tauri_plugin_dialog::init())
762â†’        .plugin(tauri_plugin_window_state::Builder::default().build())
763â†’        .manage(Mutex::new(AppState {
764â†’            watched_repos: HashSet::new(),
765â†’        }))
766â†’        .manage(Mutex::new(ghostty::GhosttyState::new()))
767â†’        .setup(|app| {
768â†’            // Start the ghostty tick loop on the MAIN THREAD via a Cocoa timer.
769â†’            // ghostty_app_tick processes Cocoa/Metal events and must run on the
770â†’            // main thread.
771â†’            {
772â†’                use block2::RcBlock;
773â†’                use objc2_foundation::NSTimer;
774â†’
775â†’                let handle = app.handle().clone();
776â†’                let tick_block = RcBlock::new(move |_timer| {
777â†’                    let state = handle.state::<Mutex<ghostty::GhosttyState>>();
778â†’                    let mutex = state.inner();
779â†’                    if let Ok(gs) = mutex.lock() {
780â†’                        if let Some(app) = gs.app.as_ref() {
781â†’                            app.tick();
782â†’                        }
783â†’                    }
784â†’                });
785â†’
786â†’                let _tick_timer = unsafe {
787â†’                    NSTimer::scheduledTimerWithTimeInterval_repeats_block(
788â†’                        1.0 / 60.0,
789â†’                        true,
790â†’                        &tick_block,
791â†’                    )
792â†’                };
793â†’            }
794â†’
795â†’            // System tray
796â†’            use tauri::menu::{MenuBuilder, MenuItemBuilder};
797â†’            use tauri::tray::TrayIconBuilder;
798â†’            use tauri::Manager;
799â†’
800â†’            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
801â†’            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
802â†’            let menu = MenuBuilder::new(app)
803â†’                .item(&show)
804â†’                .separator()
805â†’                .item(&quit)
806â†’                .build()?;
807â†’
808â†’            let _tray = TrayIconBuilder::new()
809â†’                .tooltip("Entire Desktop")
810â†’                .menu(&menu)
811â†’                .on_menu_event(move |app, event| {
812â†’                    match event.id().as_ref() {
813â†’                        "show" => {
814â†’                            if let Some(window) = app.get_webview_window("main") {
815â†’                                let _ = window.show();
816â†’                                let _ = window.set_focus();
817â†’                            }
818â†’                        }
819â†’                        "quit" => {
820â†’                            app.exit(0);
821â†’                        }
822â†’                        _ => {}
823â†’                    }
824â†’                })
825â†’                .on_tray_icon_event(|tray, event| {
826â†’                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
