 67â†’    let path = registry_path();
 68â†’    if let Some(parent) = path.parent() {
 69â†’        fs::create_dir_all(parent).map_err(|e| format!("Failed to create ~/.entire: {}", e))?;
 70â†’    }
 71â†’    let content =
 72â†’        serde_json::to_string_pretty(registry).map_err(|e| format!("Failed to serialize: {}", e))?;
 73â†’    fs::write(&path, content).map_err(|e| format!("Failed to write registry: {}", e))
 74â†’}
 75â†’
 76â†’fn save_registered_repos(repos: &[String]) -> Result<(), String> {
 77â†’    let mut registry = load_registry();
 78â†’    registry.repos = repos.to_vec();
 79â†’    save_registry(&registry)
 80â†’}
