 82â†’pub fn register_repo(path: &str) -> Result<(), String> {
 83â†’    let p = Path::new(path);
 84â†’
 85â†’    if !p.is_dir() {
 86â†’        return Err("Path is not a directory".to_string());
 87â†’    }
 88â†’
 89â†’    // Validate it's a git repo
 90â†’    git2::Repository::open(p).map_err(|_| "Not a git repository".to_string())?;
 91â†’
 92â†’    // Validate .entire is enabled
 93â†’    if !is_entire_enabled(path) {
 94â†’        return Err("Repository does not have Entire enabled (.entire/settings.json with enabled: true)".to_string());
 95â†’    }
 96â†’
 97â†’    // Canonicalize to avoid duplicates from different path representations
 98â†’    let canonical = p
 99â†’        .canonicalize()
100â†’        .map_err(|e| format!("Failed to resolve path: {}", e))?
101â†’        .to_string_lossy()
102â†’        .to_string();
103â†’
104â†’    let mut registry = load_registry();
105â†’    // Unblock if previously blocked
106â†’    registry.blocked.retain(|r| r != &canonical && r != path);
107â†’    if !registry.repos.contains(&canonical) {
108â†’        registry.repos.push(canonical);
109â†’    }
110â†’    save_registry(&registry)
111â†’}
112â†’
113â†’pub fn block_repo(path: &str) -> Result<(), String> {
114â†’    let canonical = Path::new(path)
115â†’        .canonicalize()
116â†’        .map(|p| p.to_string_lossy().to_string())
117â†’        .unwrap_or_else(|_| path.to_string());
118â†’
119â†’    let mut registry = load_registry();
120â†’    // Also unregister if it was registered
121â†’    registry.repos.retain(|r| r != &canonical && r != path);
122â†’    if !registry.blocked.contains(&canonical) {
123â†’        registry.blocked.push(canonical);
124â†’    }
125â†’    save_registry(&registry)
126â†’}
127â†’
128â†’pub fn unregister_repo(path: &str) -> Result<(), String> {
129â†’    let mut repos = load_registered_repos();
130â†’    let canonical = Path::new(path)
131â†’        .canonicalize()
132â†’        .map(|p| p.to_string_lossy().to_string())
133â†’        .unwrap_or_else(|_| path.to_string());
134â†’
135â†’    repos.retain(|r| r != &canonical && r != path);
136â†’    save_registered_repos(&repos)
137â†’}
138â†’
139â†’pub fn get_registered_repos() -> Vec<String> {
140â†’    load_registered_repos()
141â†’}
