143â†’/// Discover repos with Entire enabled by scanning common directories
144â†’pub fn discover_repos() -> Vec<String> {
145â†’    let mut seen = HashSet::new();
146â†’    let mut repos = Vec::new();
147â†’    let home = dirs_next().unwrap_or_default();
148â†’    let blocked: HashSet<String> = load_registry().blocked.into_iter().collect();
149â†’
150â†’    // Scan common project directories
151â†’    let scan_dirs = vec![
152â†’        PathBuf::from(&home).join("Projects"),
153â†’        PathBuf::from(&home).join("code"),
154â†’        PathBuf::from(&home).join("src"),
155â†’        PathBuf::from(&home).join("dev"),
156â†’    ];
157â†’
158â†’    for dir in scan_dirs {
159â†’        if dir.exists() {
160â†’            if let Ok(entries) = fs::read_dir(&dir) {
161â†’                for entry in entries.flatten() {
162â†’                    let path = entry.path();
163â†’                    if path.is_dir() && is_entire_enabled(&path.to_string_lossy()) {
164â†’                        let s = path.to_string_lossy().to_string();
165â†’                        if !blocked.contains(&s) && seen.insert(s.clone()) {
166â†’                            repos.push(s);
167â†’                        }
168â†’                    }
169â†’                }
170â†’            }
171â†’        }
172â†’    }
173â†’
174â†’    // Merge in manually registered repos
175â†’    for registered in load_registered_repos() {
176â†’        if !blocked.contains(&registered) && seen.insert(registered.clone()) {
177â†’            // Only add if the repo still exists and is still enabled
178â†’            if Path::new(&registered).is_dir() && is_entire_enabled(&registered) {
179â†’                repos.push(registered);
180â†’            }
181â†’        }
182â†’    }
183â†’
184â†’    repos
185â†’}
