 89â†’/// List all checkpoints from the entire/checkpoints/v1 branch
 90â†’pub fn list_checkpoints(
 91â†’    repo: &Repository,
 92â†’    filter_branch: &str,
 93â†’) -> Result<Vec<CheckpointSummary>, String> {
 94â†’    let branch_ref = match repo.find_branch("entire/checkpoints/v1", git2::BranchType::Local) {
 95â†’        Ok(b) => b,
 96â†’        Err(_) => return Ok(Vec::new()), // No checkpoints branch yet
 97â†’    };
 98â†’
 99â†’    let commit = branch_ref
100â†’        .get()
101â†’        .peel_to_commit()
102â†’        .map_err(|e| format!("Failed to get checkpoint commit: {}", e))?;
103â†’
104â†’    let tree = commit
105â†’        .tree()
106â†’        .map_err(|e| format!("Failed to get tree: {}", e))?;
107â†’
108â†’    let mut checkpoints = Vec::new();
109â†’
110â†’    // Walk the sharded directory structure: <id[:2]>/<id[2:]>/metadata.json
111â†’    tree.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
112â†’        let name = match entry.name() {
113â†’            Some(n) => n,
114â†’            None => return git2::TreeWalkResult::Ok,
115â†’        };
116â†’
117â†’        // Look for metadata.json at the checkpoint level (e.g., "a1/b2c3d4/metadata.json")
118â†’        if name == "metadata.json" && !dir.is_empty() {
119â†’            // dir looks like "a1/b2c3d4/" â€” that's 2 levels deep
120â†’            let parts: Vec<&str> = dir.trim_end_matches('/').split('/').collect();
121â†’            if parts.len() == 2 {
122â†’                // This is a root checkpoint metadata.json
123â†’                if let Ok(blob) = repo.find_blob(entry.id()) {
124â†’                    if let Ok(content) = std::str::from_utf8(blob.content()) {
125â†’                        if let Ok(meta) = serde_json::from_str::<RawCheckpointMetadata>(content) {
126â†’                            let branch = meta.branch.clone().unwrap_or_default();
127â†’                            if filter_branch.is_empty() || branch == filter_branch {
128â†’                                let cp = build_checkpoint_summary(
129â†’                                    repo,
130â†’                                    &tree,
131â†’                                    dir,
132â†’                                    &meta,
133â†’                                );
134â†’                                if let Ok(cp) = cp {
135â†’                                    checkpoints.push(cp);
136â†’                                }
137â†’                            }
138â†’                        }
139â†’                    }
140â†’                }
141â†’            }
142â†’        }
143â†’
144â†’        git2::TreeWalkResult::Ok
145â†’    })
146â†’    .map_err(|e| format!("Tree walk error: {}", e))?;
147â†’
148â†’    // Sort by created_at descending
149â†’    checkpoints.sort_by(|a, b| b.created_at.cmp(&a.created_at));
150â†’
151â†’    Ok(checkpoints)
152â†’}
