154â†’fn build_checkpoint_summary(
155â†’    repo: &Repository,
156â†’    _tree: &git2::Tree,
157â†’    dir: &str,
158â†’    meta: &RawCheckpointMetadata,
159â†’) -> Result<CheckpointSummary, String> {
160â†’    let checkpoint_id = meta
161â†’        .checkpoint_id
162â†’        .clone()
163â†’        .unwrap_or_else(|| dir.replace('/', ""));
164â†’
165â†’    let mut sessions = Vec::new();
166â†’    let mut earliest_created_at: Option<String> = None;
167â†’    // Read session metadata from subdirectories (0/, 1/, etc.)
168â†’    if let Some(refs) = &meta.sessions {
169â†’        for (i, session_ref) in refs.iter().enumerate() {
170â†’            let session_dir = format!("{}{}/", dir, i);
171â†’            let session_meta_path = format!("{}metadata.json", session_dir);
172â†’
173â†’            // Try to read session metadata from the tree
174â†’            if let Ok(session_meta) = read_blob_from_tree(repo, &session_meta_path) {
175â†’                if let Ok(sm) = serde_json::from_str::<RawSessionMetadata>(&session_meta) {
176â†’                    // Track earliest created_at across sessions
177â†’                    if let Some(ref ca) = sm.created_at {
178â†’                        if earliest_created_at.as_ref().map_or(true, |e| ca < e) {
179â†’                            earliest_created_at = Some(ca.clone());
180â†’                        }
181â†’                    }
182â†’
183â†’                    // Count steps from transcript if available
184â†’                    let step_count = count_transcript_steps(repo, session_ref, &session_dir);
185â†’
186â†’                    sessions.push(SessionSummary {
187â†’                        session_id: sm.session_id.unwrap_or_default(),
188â†’                        agent: sm.agent.unwrap_or_else(|| "Unknown".to_string()),
189â†’                        model: sm.model,
190â†’                        step_count,
191â†’                        summary: sm.summary,
192â†’                        token_usage: sm.token_usage,
193â†’                        initial_attribution: sm.initial_attribution,
194â†’                    });
195â†’                }
196â†’            }
197â†’        }
198â†’    }
199â†’
200â†’    // Use checkpoint metadata fields first, fall back to session-derived values
201â†’    let created_at = meta
202â†’        .created_at
203â†’        .clone()
204â†’        .or(earliest_created_at)
205â†’        .unwrap_or_default();
206â†’
207â†’    let branch_name = meta.branch.clone().unwrap_or_default();
208â†’
209â†’    // Resolve commit_sha and commit_message from the branch's git history
210â†’    // The checkpoint corresponds to the most recent commit on the branch at created_at time
211â†’    let (commit_sha, commit_message) = meta
212â†’        .commit_sha
213â†’        .clone()
214â†’        .filter(|s| !s.is_empty())
215â†’        .map(|sha| {
216â†’            let msg = meta.commit_message.clone().unwrap_or_default();
217â†’            (sha, msg)
218â†’        })
219â†’        .unwrap_or_else(|| {
220â†’            resolve_commit_from_branch(repo, &branch_name, &created_at)
221â†’                .unwrap_or_default()
222â†’        });
223â†’
224â†’    Ok(CheckpointSummary {
225â†’        checkpoint_id,
226â†’        branch: branch_name,
227â†’        commit_sha,
228â†’        commit_message,
229â†’        files_touched: meta.files_touched.clone().unwrap_or_default(),
230â†’        sessions,
231â†’        token_usage: meta.token_usage.clone(),
232â†’        created_at,
233â†’    })
234â†’}
