236â†’/// Find the most recent commit on a branch at or before the given timestamp.
237â†’/// Returns (sha, message) or None if not found.
238â†’fn resolve_commit_from_branch(
239â†’    repo: &Repository,
240â†’    branch_name: &str,
241â†’    created_at: &str,
242â†’) -> Option<(String, String)> {
243â†’    if branch_name.is_empty() || created_at.is_empty() {
244â†’        return None;
245â†’    }
246â†’
247â†’    let branch = repo.find_branch(branch_name, git2::BranchType::Local).ok()?;
248â†’    let branch_commit = branch.get().peel_to_commit().ok()?;
249â†’
250â†’    // Parse the checkpoint created_at as a unix timestamp for comparison
251â†’    let checkpoint_ts = parse_iso_timestamp(created_at)?;
252â†’
253â†’    // Walk commits from branch HEAD backward
254â†’    let mut revwalk = repo.revwalk().ok()?;
255â†’    revwalk.push(branch_commit.id()).ok()?;
256â†’    revwalk.set_sorting(git2::Sort::TIME).ok()?;
257â†’
258â†’    for oid in revwalk {
259â†’        let oid = oid.ok()?;
260â†’        let commit = repo.find_commit(oid).ok()?;
261â†’        let commit_ts = commit.time().seconds();
262â†’
263â†’        // Find the first commit whose time is at or before the checkpoint
264â†’        if commit_ts <= checkpoint_ts {
265â†’            let sha = oid.to_string();
266â†’            let message = commit
267â†’                .summary()
268â†’                .unwrap_or("")
269â†’                .to_string();
270â†’            return Some((sha, message));
271â†’        }
272â†’    }
273â†’
274â†’    None
275â†’}
