277â†’/// Parse an ISO 8601 timestamp string to unix seconds
278â†’fn parse_iso_timestamp(s: &str) -> Option<i64> {
279â†’    // Handle formats like "2026-03-16T21:10:30.808196Z" and "2026-03-16T21:10:30Z"
280â†’    let s = s.trim();
281â†’    // Strip fractional seconds and Z
282â†’    let s = s.trim_end_matches('Z');
283â†’    let s = if let Some(dot_pos) = s.rfind('.') {
284â†’        &s[..dot_pos]
285â†’    } else {
286â†’        s
287â†’    };
288â†’
289â†’    // Parse "YYYY-MM-DDTHH:MM:SS"
290â†’    let parts: Vec<&str> = s.split('T').collect();
291â†’    if parts.len() != 2 {
292â†’        return None;
293â†’    }
294â†’    let date_parts: Vec<i64> = parts[0].split('-').filter_map(|p| p.parse().ok()).collect();
295â†’    let time_parts: Vec<i64> = parts[1].split(':').filter_map(|p| p.parse().ok()).collect();
296â†’
297â†’    if date_parts.len() != 3 || time_parts.len() != 3 {
298â†’        return None;
299â†’    }
300â†’
301â†’    let (year, month, day) = (date_parts[0], date_parts[1], date_parts[2]);
302â†’    let (hour, min, sec) = (time_parts[0], time_parts[1], time_parts[2]);
303â†’
304â†’    // Simple days-since-epoch calculation (good enough for comparison)
305â†’    let mut days: i64 = 0;
306â†’    for y in 1970..year {
307â†’        days += if y % 4 == 0 && (y % 100 != 0 || y % 400 == 0) { 366 } else { 365 };
308â†’    }
309â†’    let month_days = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
310â†’    let is_leap = year % 4 == 0 && (year % 100 != 0 || year % 400 == 0);
311â†’    for m in 1..month {
312â†’        days += month_days[m as usize];
313â†’        if m == 2 && is_leap {
314â†’            days += 1;
315â†’        }
316â†’    }
317â†’    days += day - 1;
318â†’
319â†’    Some(days * 86400 + hour * 3600 + min * 60 + sec)
320â†’}
