 68â†’pub fn list_worktrees(repo: &Repository) -> Result<Vec<WorktreeInfo>, String> {
 69â†’    let mut worktrees = Vec::new();
 70â†’    let wt_names = repo
 71â†’        .worktrees()
 72â†’        .map_err(|e| format!("Failed to list worktrees: {}", e))?;
 73â†’
 74â†’    for name in wt_names.iter() {
 75â†’        if let Some(name) = name {
 76â†’            if let Ok(wt) = repo.find_worktree(name) {
 77â†’                let wt_path = wt.path().to_string_lossy().to_string();
 78â†’                // Try to detect branch from worktree
 79â†’                let branch = detect_worktree_branch(&wt_path).unwrap_or_else(|| name.to_string());
 80â†’                worktrees.push(WorktreeInfo {
 81â†’                    path: wt_path,
 82â†’                    branch,
 83â†’                    is_main: false,
 84â†’                });
 85â†’            }
 86â†’        }
 87â†’    }
 88â†’
 89â†’    Ok(worktrees)
 90â†’}
