 92â†’fn detect_worktree_branch(wt_path: &str) -> Option<String> {
 93â†’    let head_path = Path::new(wt_path).join(".git");
 94â†’    // Worktree .git is a file pointing to the main repo's worktree dir
 95â†’    if head_path.is_file() {
 96â†’        if let Ok(repo) = Repository::open(wt_path) {
 97â†’            if let Ok(head) = repo.head() {
 98â†’                return head.shorthand().map(|s| s.to_string());
 99â†’            }
100â†’        }
101â†’    }
102â†’    None
103â†’}
