214â†’pub fn delete_worktree(
215â†’    repo_path: &str,
216â†’    worktree_path: &str,
217â†’    branch_name: &str,
218â†’    force: bool,
219â†’) -> Result<(), String> {
220â†’    if branch_name.trim().is_empty() {
221â†’        return Err("Branch name is required".to_string());
222â†’    }
223â†’    if worktree_path.trim().is_empty() {
224â†’        return Err("Worktree path is required".to_string());
225â†’    }
226â†’    if paths_match(repo_path, worktree_path) {
227â†’        return Err("Cannot delete the main repository checkout".to_string());
228â†’    }
229â†’
230â†’    open_repo(repo_path)?;
231â†’
232â†’    let remove_args = build_git_worktree_remove_args(worktree_path.trim(), force);
233â†’    run_git_command(repo_path, &remove_args)?;
234â†’
235â†’    let delete_args = build_git_branch_delete_args(branch_name.trim(), force);
236â†’    run_git_command(repo_path, &delete_args)
237â†’}
