239â†’fn run_git_command(repo_path: &str, args: &[String]) -> Result<(), String> {
240â†’    let output = Command::new("git")
241â†’        .args(args)
242â†’        .current_dir(repo_path)
243â†’        .output()
244â†’        .map_err(|e| format!("Failed to run git: {}", e))?;
245â†’
246â†’    if output.status.success() {
247â†’        return Ok(());
248â†’    }
249â†’
250â†’    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
251â†’    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
252â†’    let message = if !stderr.is_empty() {
253â†’        stderr
254â†’    } else if !stdout.is_empty() {
255â†’        stdout
256â†’    } else {
257â†’        "Git command failed".to_string()
258â†’    };
259â†’
260â†’    Err(message)
261â†’}
