263â†’fn paths_match(left: &str, right: &str) -> bool {
264â†’    let left = std::fs::canonicalize(left).ok();
265â†’    let right = std::fs::canonicalize(right).ok();
266â†’    matches!((left, right), (Some(left), Some(right)) if left == right)
267â†’}
