269â†’/// Count checkpoints per branch by walking the checkpoint tree
270â†’fn count_checkpoints_per_branch(repo: &Repository) -> std::collections::HashMap<String, u32> {
271â†’    let mut counts = std::collections::HashMap::new();
272â†’
273â†’    let branch_ref = match repo.find_branch("entire/checkpoints/v1", git2::BranchType::Local) {
274â†’        Ok(b) => b,
275â†’        Err(_) => return counts,
276â†’    };
277â†’
278â†’    let commit = match branch_ref.get().peel_to_commit() {
279â†’        Ok(c) => c,
280â†’        Err(_) => return counts,
281â†’    };
282â†’
283â†’    let tree = match commit.tree() {
284â†’        Ok(t) => t,
285â†’        Err(_) => return counts,
286â†’    };
287â†’
288â†’    let _ = tree.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
289â†’        let name = match entry.name() {
290â†’            Some(n) => n,
291â†’            None => return git2::TreeWalkResult::Ok,
292â†’        };
293â†’
294â†’        if name == "metadata.json" && !dir.is_empty() {
295â†’            let parts: Vec<&str> = dir.trim_end_matches('/').split('/').collect();
296â†’            if parts.len() == 2 {
297â†’                if let Ok(blob) = repo.find_blob(entry.id()) {
298â†’                    if let Ok(content) = std::str::from_utf8(blob.content()) {
299â†’                        // Quick parse just the branch field
300â†’                        if let Ok(val) = serde_json::from_str::<serde_json::Value>(content) {
301â†’                            if let Some(branch) = val.get("branch").and_then(|b| b.as_str()) {
302â†’                                *counts.entry(branch.to_string()).or_insert(0) += 1;
303â†’                            }
304â†’                        }
305â†’                    }
306â†’                }
307â†’            }
308â†’        }
309â†’
310â†’        git2::TreeWalkResult::Ok
311â†’    });
312â†’
313â†’    counts
314â†’}
