423â†’/// Convert a git2::Diff into our FileDiff structs
424â†’fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
425â†’    let mut files: Vec<FileDiff> = Vec::new();
426â†’
427â†’    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
428â†’        let path = delta
429â†’            .new_file()
430â†’            .path()
431â†’            .or_else(|| delta.old_file().path())
432â†’            .map(|p| p.to_string_lossy().to_string())
433â†’            .unwrap_or_default();
434â†’
435â†’        let status = match delta.status() {
436â†’            git2::Delta::Added => "added",
437â†’            git2::Delta::Deleted => "deleted",
438â†’            _ => "modified",
439â†’        };
440â†’
441â†’        // Ensure we have a FileDiff entry for this path
442â†’        if files.last().map_or(true, |f| f.path != path) {
443â†’            files.push(FileDiff {
444â†’                path: path.clone(),
445â†’                status: status.to_string(),
446â†’                hunks: Vec::new(),
447â†’            });
448â†’        }
449â†’
450â†’        let file = files.last_mut().unwrap();
451â†’
452â†’        // New hunk
453â†’        if let Some(h) = hunk {
454â†’            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
455â†’            if file.hunks.last().map_or(true, |last| last.header != header) {
456â†’                file.hunks.push(DiffHunk {
457â†’                    header,
458â†’                    lines: Vec::new(),
459â†’                });
460â†’            }
461â†’        }
462â†’
463â†’        // Diff line
464â†’        if let Some(current_hunk) = file.hunks.last_mut() {
465â†’            let kind = match line.origin() {
466â†’                '+' => "add",
467â†’                '-' => "delete",
468â†’                ' ' => "context",
469â†’                _ => return true,
470â†’            };
471â†’            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
472â†’            current_hunk.lines.push(DiffLine {
473â†’                kind: kind.to_string(),
474â†’                content,
475â†’                old_lineno: line.old_lineno(),
476â†’                new_lineno: line.new_lineno(),
477â†’            });
478â†’        }
479â†’
480â†’        true
481â†’    })
482â†’    .map_err(|e| format!("Failed to print diff: {}", e))?;
483â†’
484â†’    Ok(files)
485â†’}
