672â†’    let repo = git::open_repo(&repo_path)?;
673â†’
674â†’    // Resolve the branch HEAD
675â†’    let branch_ref = repo
676â†’        .find_branch(&branch, git2::BranchType::Local)
677â†’        .map_err(|e| format!("Branch not found: {}", e))?;
678â†’    let branch_commit = branch_ref
679â†’        .get()
680â†’        .peel_to_commit()
681â†’        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
682â†’
683â†’    // Find the default branch (try main, then master)
684â†’    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
685â†’        "main"
686â†’    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
687â†’        "master"
688â†’    } else {
689â†’        return Err("No default branch (main/master) found".to_string());
690â†’    };
691â†’
692â†’    // If we're diffing the default branch against itself, return empty
693â†’    if branch == default_branch_name {
694â†’        return Ok(Vec::new());
695â†’    }
696â†’
697â†’    let default_ref = repo
698â†’        .find_branch(default_branch_name, git2::BranchType::Local)
699â†’        .map_err(|e| format!("Default branch error: {}", e))?;
700â†’    let default_commit = default_ref
701â†’        .get()
702â†’        .peel_to_commit()
703â†’        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
704â†’
705â†’    // Find merge base
706â†’    let merge_base_oid = repo
707â†’        .merge_base(default_commit.id(), branch_commit.id())
708â†’        .map_err(|e| format!("Failed to find merge base: {}", e))?;
709â†’    let merge_base_commit = repo
710â†’        .find_commit(merge_base_oid)
711â†’        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
712â†’
