228â†’/// Parse a journal markdown file into a JournalEntry.
229â†’pub fn parse_markdown(content: &str) -> Result<JournalEntry, String> {
230â†’    // Split frontmatter from body
231â†’    let (frontmatter, body) = split_frontmatter(content)?;
232â†’
233â†’    // Parse YAML frontmatter
234â†’    let date = extract_yaml_field(&frontmatter, "date")
235â†’        .ok_or("Missing date in frontmatter")?;
236â†’    let generated_at = extract_yaml_field(&frontmatter, "generated_at")
237â†’        .unwrap_or_default();
238â†’    let stats = parse_frontmatter_only(content)?;
239â†’
240â†’    // Parse body into repo sections and other work
241â†’    let (repos, other_work) = parse_body(&body);
242â†’
243â†’    Ok(JournalEntry {
