252â†’fn split_frontmatter(content: &str) -> Result<(String, String), String> {
253â†’    let content = content.trim();
254â†’    if !content.starts_with("---") {
255â†’        return Err("No frontmatter found".to_string());
256â†’    }
257â†’    let rest = &content[3..];
258â†’    let end = rest.find("---").ok_or("Unterminated frontmatter")?;
259â†’    let frontmatter = rest[..end].trim().to_string();
260â†’    let body = rest[end + 3..].trim().to_string();
261â†’    Ok((frontmatter, body))
262â†’}
