264â†’fn extract_yaml_field(yaml: &str, field: &str) -> Option<String> {
265â†’    for line in yaml.lines() {
266â†’        let line = line.trim();
267â†’        if let Some(rest) = line.strip_prefix(&format!("{}:", field)) {
268â†’            let value = rest.trim().trim_matches('"').trim_matches('\'');
269â†’            if !value.is_empty() {
270â†’                return Some(value.to_string());
271â†’            }
272â†’        }
273â†’    }
274â†’    None
275â†’}
