305â†’fn parse_body(body: &str) -> (Vec<RepoSection>, Vec<String>) {
306â†’    let mut repos = Vec::new();
307â†’    let mut other_work = Vec::new();
308â†’    let mut current_repo: Option<RepoSection> = None;
309â†’    let mut in_prs = false;
310â†’    let mut in_other_work = false;
311â†’
312â†’    for line in body.lines() {
313â†’        let trimmed = line.trim();
314â†’
315â†’        // H2 heading = repo name or "Other Work"
316â†’        if let Some(heading) = trimmed.strip_prefix("## ") {
317â†’            // Save previous repo
318â†’            if let Some(repo) = current_repo.take() {
319â†’                repos.push(repo);
320â†’            }
321â†’            in_prs = false;
322â†’
323â†’            if heading == "Other Work" {
324â†’                in_other_work = true;
325â†’                continue;
326â†’            }
327â†’
328â†’            in_other_work = false;
329â†’            current_repo = Some(RepoSection {
330â†’                name: heading.to_string(),
331â†’                lines_added: 0,
332â†’                lines_removed: 0,
333â†’                accomplishments: Vec::new(),
334â†’                pull_requests: Vec::new(),
335â†’            });
336â†’            continue;
337â†’        }
338â†’
339â†’        // H3 heading = "Pull Requests" subsection
340â†’        if trimmed.starts_with("### Pull Requests") {
341â†’            in_prs = true;
342â†’            continue;
343â†’        }
344â†’
345â†’        // Lines diff stats: _+716 -131_
346â†’        if trimmed.starts_with("_+") && trimmed.ends_with('_') {
347â†’            if let Some(ref mut repo) = current_repo {
348â†’                let inner = &trimmed[1..trimmed.len() - 1];
349â†’                let parts: Vec<&str> = inner.split_whitespace().collect();
350â†’                if parts.len() == 2 {
351â†’                    repo.lines_added = parts[0].trim_start_matches('+').parse().unwrap_or(0);
352â†’                    repo.lines_removed = parts[1].trim_start_matches('-').parse().unwrap_or(0);
353â†’                }
354â†’            }
355â†’            continue;
356â†’        }
357â†’
358â†’        // Bullet points
359â†’        if let Some(bullet_content) = trimmed.strip_prefix("- ") {
360â†’            if in_other_work {
361â†’                other_work.push(bullet_content.to_string());
362â†’            } else if in_prs {
363â†’                if let Some(ref mut repo) = current_repo {
364â†’                    if let Some(pr) = parse_pr_line(bullet_content) {
365â†’                        repo.pull_requests.push(pr);
366â†’                    }
367â†’                }
368â†’            } else if let Some(ref mut repo) = current_repo {
369â†’                repo.accomplishments.push(bullet_content.to_string());
370â†’            }
371â†’        }
372â†’    }
373â†’
374â†’    // Don't forget last repo
375â†’    if let Some(repo) = current_repo {
376â†’        repos.push(repo);
377â†’    }
378â†’
379â†’    (repos, other_work)
380â†’}
