382â†’/// Parse a PR line like: **Settings page rebuild** #142 â€” merged
383â†’fn parse_pr_line(line: &str) -> Option<JournalPR> {
384â†’    // Pattern: **title** #number â€” status
385â†’    let bold_start = line.find("**")?;
386â†’    let bold_end = line[bold_start + 2..].find("**")? + bold_start + 2;
387â†’    let title = line[bold_start + 2..bold_end].to_string();
388â†’
389â†’    let rest = &line[bold_end + 2..];
390â†’    let hash_pos = rest.find('#')?;
391â†’    let after_hash = &rest[hash_pos + 1..];
392â†’
393â†’    // Find the number (digits until non-digit)
394â†’    let num_end = after_hash.find(|c: char| !c.is_ascii_digit()).unwrap_or(after_hash.len());
395â†’    let number: u64 = after_hash[..num_end].parse().ok()?;
396â†’
397â†’    // Find status after â€” or -
398â†’    let status = if let Some(dash_pos) = rest.find('â€”').or_else(|| rest.find(" - ")) {
399â†’        let s = rest[dash_pos..].trim_start_matches('â€”').trim_start_matches(" - ").trim();

400â†’        s.to_string()
401â†’    } else {
402â†’        "open".to_string()
403â†’    };
404â†’
405â†’    Some(JournalPR {
406â†’        title,
407â†’        number,
408â†’        status,
409â†’        additions: 0,
410â†’        deletions: 0,
411â†’        url: String::new(),
412â†’    })
413â†’}
