484â†’fn subtract_days(date: &str, n: i64) -> String {
485â†’    // Parse YYYY-MM-DD, subtract n days, return YYYY-MM-DD
486â†’    let parts: Vec<i64> = date.split('-').filter_map(|p| p.parse().ok()).collect();
487â†’    if parts.len() != 3 {
488â†’        return date.to_string();
489â†’    }
490â†’    let total_days = ymd_to_days(parts[0], parts[1], parts[2]) - n;
491â†’    let (y, m, d) = days_to_ymd(total_days);
492â†’    format!("{:04}-{:02}-{:02}", y, m, d)
493â†’}
494â†’
495â†’fn ymd_to_days(year: i64, month: i64, day: i64) -> i64 {
496â†’    let mut days: i64 = 0;
497â†’    for y in 1970..year {
498â†’        days += if is_leap(y) { 366 } else { 365 };
499â†’    }
500â†’    let month_lengths = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
501â†’    for m in 1..month {
502â†’        days += month_lengths[m as usize];
503â†’        if m == 2 && is_leap(year) {
504â†’            days += 1;
505â†’        }
506â†’    }
507â†’    days + day - 1
508â†’}
509â†’
510â†’fn days_to_ymd(mut days: i64) -> (i64, i64, i64) {
511â†’    let mut year = 1970;
512â†’    loop {
513â†’        let year_days = if is_leap(year) { 366 } else { 365 };
514â†’        if days < year_days {
515â†’            break;
516â†’        }
517â†’        days -= year_days;
518â†’        year += 1;
519â†’    }
520â†’    let month_lengths = if is_leap(year) {
521â†’        [31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
522â†’    } else {
523â†’        [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
524â†’    };
525â†’    let mut month = 1;
526â†’    for &ml in &month_lengths {
527â†’        if days < ml {
528â†’            break;
529â†’        }
530â†’        days -= ml;
531â†’        month += 1;
532â†’    }
533â†’    (year, month, days + 1)
534â†’}
535â†’
536â†’fn is_leap(y: i64) -> bool {
537â†’    y % 4 == 0 && (y % 100 != 0 || y % 400 == 0)
538â†’}
