646â†’    let url = remote_url.trim().trim_end_matches(".git");
647â†’
648â†’    // SSH: git@github.com:owner/repo
649â†’    if let Some(rest) = url.strip_prefix("git@github.com:") {
650â†’        let parts: Vec<&str> = rest.splitn(2, '/').collect();
