652â†’            return Some((parts[0].to_string(), parts[1].to_string()));
653â†’        }
654â†’    }
655â†’
656â†’    // HTTPS: https://github.com/owner/repo
657â†’    if url.contains("github.com/") {
658â†’        let after = url.split("github.com/").nth(1)?;
659â†’        let parts: Vec<&str> = after.splitn(2, '/').collect();
660â†’        if parts.len() == 2 {
661â†’            return Some((parts[0].to_string(), parts[1].to_string()));
662â†’        }
663â†’    }
664â†’
665â†’    None
